-- GREETING — A1
-- ══════════════════════════════════════
UPDATE sentences SET ex1 = 'Nice to meet you, Mr. Park — I''ve been looking forward to today.', ex1_ko = '만나서 반갑습니다, 박 선생님 — 오늘을 기다리고 있었어요.', ex2 = 'Nice to meet you! I''m Jiwon, your new neighbor.', ex2_ko = '만나서 반가워요! 저는 새 이웃 지원이에요.', ex3 = 'Nice to meet you — Minho has told me so much about your work.', ex3_ko = '만나서 반가워요 — 민호한테 일하시는 얘기 정말 많이 들었어요.', ex4 = 'Nice to meet you in person finally, after all those emails.', ex4_ko = '그 많던 이메일 끝에 드디어 직접 만나서 반갑습니다.', ex5 = 'Nice to meet you! Please feel free to call me Sarah.', ex5_ko = '만나서 반가워요! 그냥 사라라고 불러 주세요.' WHERE id = 's_greeting_A1_01';
UPDATE sentences SET ex1 = 'How are you? I haven''t seen you since last Christmas.', ex1_ko = '어떻게 지내세요? 작년 크리스마스 이후로 못 봤네요.', ex2 = 'How are you today, Ms. Kim? Did you have a good weekend?', ex2_ko = '오늘 어떻게 지내세요, 김 선생님? 주말은 잘 보내셨어요?', ex3 = 'How are you? You look like you''ve been busy lately.', ex3_ko = '어떻게 지내세요? 요즘 바빠 보이시네요.', ex4 = 'How are you? I heard you started a new job last month.', ex4_ko = '어떻게 지내세요? 지난달에 새 직장 시작하셨다고 들었어요.', ex5 = 'How are you doing? Long time no see!', ex5_ko = '어떻게 지내세요? 진짜 오랜만이에요!' WHERE id = 's_greeting_A1_02';
UPDATE sentences SET ex1 = 'Good morning! How are you today? It''s a beautiful day, isn''t it?', ex1_ko = '좋은 아침이에요! 오늘 어떻게 지내세요? 날씨가 정말 좋네요, 그렇죠?', ex2 = 'Good morning, everyone! How are you today? Ready for the meeting?', ex2_ko = '좋은 아침이에요, 여러분! 오늘 어떻게 지내세요? 회의 준비됐어요?', ex3 = 'Good morning, Mr. Lee! How are you today? Did you sleep well?', ex3_ko = '좋은 아침이에요, 이 선생님! 오늘 어떻게 지내세요? 잘 주무셨어요?', ex4 = 'Good morning! How are you today? You look much better than yesterday.', ex4_ko = '좋은 아침이에요! 오늘 어떻게 지내세요? 어제보다 훨씬 좋아 보이시네요.', ex5 = 'Good morning, Sue! How are you today? Hope you had your coffee.', ex5_ko = '좋은 아침이에요, 수! 오늘 어떻게 지내세요? 커피는 드셨길 바라요.' WHERE id = 's_greeting_A1_03';
UPDATE sentences SET ex1 = 'My name is Suyeon. What''s your name?', ex1_ko = '제 이름은 수연이에요. 성함이 어떻게 되세요?', ex2 = 'Hi, my name is David. What''s your name? Are you here for the workshop?', ex2_ko = '안녕하세요, 제 이름은 데이비드예요. 성함이 어떻게 되세요? 워크숍 때문에 오셨어요?', ex3 = 'My name is Hana — I''m new here. What''s your name?', ex3_ko = '제 이름은 하나예요 — 여기 처음이에요. 성함이 어떻게 되세요?', ex4 = 'My name is Joon. What''s your name? Which class are you in?', ex4_ko = '제 이름은 준이에요. 성함이 어떻게 되세요? 어떤 반이세요?', ex5 = 'My name is Mr. Choi. What''s your name, young man?', ex5_ko = '제 이름은 최 선생이에요. 성함이 어떻게 되시나요, 학생?' WHERE id = 's_greeting_A1_04';
UPDATE sentences SET ex1 = 'Thank you so much for the gift! You''re very kind.', ex1_ko = '선물 정말 감사해요! 정말 친절하시네요.', ex2 = 'Thank you so much for helping me move yesterday. You''re very kind.', ex2_ko = '어제 이사 도와주셔서 정말 감사해요. 정말 친절하시네요.', ex3 = 'Thank you so much for staying late with me. You''re very kind.', ex3_ko = '저랑 늦게까지 같이 있어 주셔서 정말 감사해요. 정말 친절하시네요.', ex4 = 'Thank you so much for the warm welcome! You''re very kind.', ex4_ko = '따뜻하게 맞아 주셔서 정말 감사해요! 정말 친절하시네요.', ex5 = 'Thank you so much for the home-cooked meal — you''re very kind.', ex5_ko = '집밥 차려 주셔서 정말 감사해요 — 정말 친절하시네요.' WHERE id = 's_greeting_A1_05';
UPDATE sentences SET ex1 = 'Goodbye! See you later — I had a great time tonight.', ex1_ko = '안녕히 가세요! 나중에 봐요 — 오늘 밤 정말 즐거웠어요.', ex2 = 'Goodbye, everyone! See you later at the cafe!', ex2_ko = '여러분 안녕히 가세요! 카페에서 이따 봐요!', ex3 = 'Goodbye, Mom! See you later this weekend.', ex3_ko = '엄마 안녕히 계세요! 이번 주말에 봐요.', ex4 = 'Goodbye! See you later — text me when you get home, okay?', ex4_ko = '안녕히 가세요! 나중에 봐요 — 집에 도착하면 문자해요, 알았죠?', ex5 = 'Goodbye! See you later — drive safely!', ex5_ko = '안녕히 가세요! 나중에 봐요 — 운전 조심히 하세요!' WHERE id = 's_greeting_A1_06';
UPDATE sentences SET ex1 = 'I''m sorry, I don''t understand. Can you say that again more slowly?', ex1_ko = '죄송해요, 이해를 못 했어요. 좀 더 천천히 다시 말씀해 주시겠어요?', ex2 = 'I''m sorry, I don''t understand. Can you say that again in English?', ex2_ko = '죄송해요, 이해를 못 했어요. 영어로 다시 말씀해 주시겠어요?', ex3 = 'I''m sorry, I don''t understand the question. Can you say that again?', ex3_ko = '죄송해요, 질문을 이해 못 했어요. 다시 말씀해 주시겠어요?', ex4 = 'I''m sorry, I don''t understand the last word. Can you say that again?', ex4_ko = '죄송해요, 마지막 단어를 이해 못 했어요. 다시 말씀해 주시겠어요?', ex5 = 'I''m sorry, I don''t understand — the line is bad. Can you say that again?', ex5_ko = '죄송해요, 이해 못 했어요 — 연결 상태가 안 좋아요. 다시 말씀해 주시겠어요?' WHERE id = 's_greeting_A1_07';

