UPDATE sentences SET ex1 = 'Let me introduce myself — I''m Jiyeon and I work as a designer at a startup.', ex1_ko = '제 소개를 할게요 — 저는 지연이고 스타트업에서 디자이너로 일해요.', ex2 = 'Let me introduce myself — I''m Mark and I work as a translator from home.', ex2_ko = '제 소개를 할게요 — 저는 마크이고 집에서 번역가로 일해요.', ex3 = 'Let me introduce myself before we start — I''m Hyunwoo and I work as an engineer.', ex3_ko = '시작하기 전에 제 소개를 할게요 — 저는 현우이고 엔지니어로 일해요.', ex4 = 'Let me introduce myself properly — I''m Soyeon and I work as a music teacher.', ex4_ko = '제대로 제 소개를 할게요 — 저는 소연이고 음악 선생님으로 일해요.', ex5 = 'Let me introduce myself — I''m Daniel and I work as a freelance writer.', ex5_ko = '제 소개를 할게요 — 저는 다니엘이고 프리랜서 작가로 일해요.' WHERE id = 's_greeting_A2_01';
UPDATE sentences SET ex1 = 'It''s lovely to meet you. I''ve heard a lot about you from your sister.', ex1_ko = '만나서 반가워요. 동생분한테 얘기 많이 들었어요.', ex2 = 'It''s lovely to meet you, Dr. Han. I''ve heard a lot about your research.', ex2_ko = '만나서 반가워요, 한 박사님. 연구에 관한 얘기 많이 들었어요.', ex3 = 'It''s lovely to meet you. I''ve heard a lot about you from the team.', ex3_ko = '만나서 반가워요. 팀원들한테 얘기 많이 들었어요.', ex4 = 'It''s lovely to meet you. I''ve heard a lot about your travels in Europe.', ex4_ko = '만나서 반가워요. 유럽 여행 얘기 많이 들었어요.', ex5 = 'It''s lovely to meet you. I''ve heard a lot about your cooking — Junho can''t stop talking about it.', ex5_ko = '만나서 반가워요. 요리 얘기 많이 들었어요 — 준호가 계속 얘기하더라고요.' WHERE id = 's_greeting_A2_02';
UPDATE sentences SET ex1 = 'Please call me Sue. It''s easier than my full name, Soohyun.', ex1_ko = '그냥 수라고 불러 주세요. 풀네임 수현보다 편해요.', ex2 = 'Please call me Tom. It''s easier than Thomas Edward Lawrence.', ex2_ko = '그냥 톰이라고 불러 주세요. 토마스 에드워드 로렌스보다 편해요.', ex3 = 'Please call me Jay. It''s easier than my full name in Korean.', ex3_ko = '그냥 제이라고 불러 주세요. 한국어 풀네임보다 편해요.', ex4 = 'Please call me Ms. Park. It''s easier than my full title in the office.', ex4_ko = '그냥 박 매니저라고 불러 주세요. 사무실 정식 직함보다 편해요.', ex5 = 'Please call me by my first name. It''s easier than the formal one.', ex5_ko = '이름으로 그냥 불러 주세요. 격식 있는 호칭보다 편해요.' WHERE id = 's_greeting_A2_03';
UPDATE sentences SET ex1 = 'It was great seeing you. Take care — and say hi to your family for me.', ex1_ko = '만나서 좋았어요. 잘 지내요 — 가족분들께도 안부 전해 주세요.', ex2 = 'It was great seeing you again after so long. Take care!', ex2_ko = '오랜만에 다시 만나서 좋았어요. 잘 지내요!', ex3 = 'It was great seeing you tonight. Take care driving home.', ex3_ko = '오늘 밤 만나서 좋았어요. 운전 조심해서 가세요.', ex4 = 'It was great seeing you at the wedding. Take care, and we''ll catch up soon.', ex4_ko = '결혼식에서 만나서 좋았어요. 잘 지내요, 곧 다시 만나요.', ex5 = 'It was great seeing you at the conference. Take care and keep in touch.', ex5_ko = '컨퍼런스에서 만나서 좋았어요. 잘 지내고 연락해요.' WHERE id = 's_greeting_A2_04';
UPDATE sentences SET ex1 = 'I''m originally from Busan but I''ve lived in Seoul for ten years. Where are you from?', ex1_ko = '저는 원래 부산 출신인데 서울에서 10년 살았어요. 어디서 오셨어요?', ex2 = 'I''m originally from a small town near Daegu. Where are you from?', ex2_ko = '저는 원래 대구 근처의 작은 동네 출신이에요. 어디서 오셨어요?', ex3 = 'I''m originally from Jeju Island, actually. Where are you from?', ex3_ko = '저는 사실 원래 제주도 출신이에요. 어디서 오셨어요?', ex4 = 'I''m originally from Canada but I moved here after college. Where are you from?', ex4_ko = '저는 원래 캐나다 출신인데 대학 졸업하고 여기로 왔어요. 어디서 오셨어요?', ex5 = 'I''m originally from a coastal city. Where are you from? You sound like you''re not from around here.', ex5_ko = '저는 원래 바닷가 도시 출신이에요. 어디서 오셨어요? 여기 분 같지 않으셔서요.' WHERE id = 's_greeting_A2_05';
UPDATE sentences SET ex1 = 'Would you mind if I joined you for lunch? The other tables are all full.', ex1_ko = '점심 합석해도 될까요? 다른 자리는 다 찼어요.', ex2 = 'Would you mind if I joined you on the walk back to the office?', ex2_ko = '사무실 돌아가는 길에 같이 걸어가도 될까요?', ex3 = 'Would you mind if I joined you at this table? It looks like a quiet spot.', ex3_ko = '이 자리에 합석해도 될까요? 조용해 보여서요.', ex4 = 'Would you mind if I joined you on the project? I have some free time.', ex4_ko = '그 프로젝트에 함께 해도 될까요? 시간이 좀 있어서요.', ex5 = 'Would you mind if I joined you for a drink after work tonight?', ex5_ko = '오늘 퇴근 후에 같이 한잔해도 될까요?' WHERE id = 's_greeting_A2_06';
UPDATE sentences SET ex1 = 'Thanks for having me — I really enjoyed the dinner and conversation.', ex1_ko = '초대해 주셔서 감사해요 — 저녁과 대화 정말 즐거웠어요.', ex2 = 'Thanks for having me at your housewarming — I really enjoyed it.', ex2_ko = '집들이에 초대해 주셔서 감사해요 — 정말 즐거웠어요.', ex3 = 'Thanks for having me on the show today — I really enjoyed our chat.', ex3_ko = '오늘 방송에 초대해 주셔서 감사해요 — 대화 정말 즐거웠어요.', ex4 = 'Thanks for having me over for the weekend — I really enjoyed it.', ex4_ko = '주말 동안 초대해 주셔서 감사해요 — 정말 즐거웠어요.', ex5 = 'Thanks for having me at the office tour — I really enjoyed it.', ex5_ko = '사무실 투어에 초대해 주셔서 감사해요 — 정말 즐거웠어요.' WHERE id = 's_greeting_A2_07';

